func TestIntentRouter_ConcurrentAccess(t *testing.T) {
	mockClient := newMockNATSClient()

	// Mock capability response
	mockClient.requestFunc = func(ctx context.Context, subject string, data []byte, timeout time.Duration) ([]byte, error) {
		if subject == "graph.ingest.capabilities" {
			caps := component.QueryCapabilities{
				Component: "graph-ingest",
				Version:   "1.0.0",
				Queries: []component.QueryCapability{
					{
						Subject:    "graph.ingest.query.entity",
						Operation:  "getEntity",
						IntentTags: []string{component.IntentTagEntity},
					},
				},
			}
			return json.Marshal(caps)
		}
		return nil, nats.ErrTimeout
	}

	router := NewIntentRouter(mockClient, slog.Default())

	// Discover capabilities (populates routes)
	err := router.DiscoverCapabilities(context.Background(), 1*time.Second)
	require.NoError(t, err)

	// Concurrent reads and writes
	var wg sync.WaitGroup
	iterations := 100

	// Concurrent readers
	for i := 0; i < 10; i++ {
		wg.Add(1)
		go func() {
			defer wg.Done()
			for j := 0; j < iterations; j++ {
				// Read operations (should not panic or deadlock)
				_ = router.Route(component.IntentTagEntity)
				_ = router.HasDiscoveredRoute(component.IntentTagEntity)
				_ = router.RouteCount()
			}
		}()
	}

	// Concurrent discovery (writes to routes map)
	for i := 0; i < 3; i++ {
		wg.Add(1)
		go func() {
			defer wg.Done()
			for j := 0; j < iterations/10; j++ {
				// Write operation (discovery updates routes map)
				_ = router.DiscoverCapabilities(context.Background(), 1*time.Second)
			}
		}()
	}

	// Wait for all goroutines with timeout
	done := make(chan struct{})
	go func() {
		wg.Wait()
		close(done)
	}()

	select {
	case <-done:
		// Success - no deadlock
	case <-time.After(5 * time.Second):
		t.Fatal("concurrent access caused deadlock")
	}

	// Verify router still works after concurrent access
	subject := router.Route(component.IntentTagEntity)
	assert.NotEmpty(t, subject, "router should still function after concurrent access")
}

