func TestIntentRouter_DiscoverCapabilities_LastWins(t *testing.T) {
	mockClient := newMockNATSClient()

	// Two components claim the same intent tag - last one should win
	requestCount := 0
	mockClient.requestFunc = func(ctx context.Context, subject string, data []byte, timeout time.Duration) ([]byte, error) {
		requestCount++
		switch subject {
		case "graph.ingest.capabilities":
			return []byte(`{
				"component": "graph-ingest",
				"version": "1.0.0",
				"queries": [
					{
						"subject": "graph.ingest.query.entity.v1",
						"operation": "getEntity",
						"intent_tags": ["entity"]
					}
				]
			}`), nil

		case "graph.index.capabilities":
			// Processed after graph.ingest - should override
			return []byte(`{
				"component": "graph-index",
				"version": "1.0.0",
				"queries": [
					{
						"subject": "graph.index.query.entity.v2",
						"operation": "getEntityIndexed",
						"intent_tags": ["entity"]
					}
				]
			}`), nil

		default:
			return nil, nats.ErrTimeout
		}
	}

	router := NewIntentRouter(mockClient, slog.Default())
	err := router.DiscoverCapabilities(context.Background(), 1*time.Second)

	assert.NoError(t, err)

	// Since capabilityEndpoints is called in order, we can't guarantee which wins
	// But we can verify that ONE of them is the discovered route
	subject := router.Route(component.IntentTagEntity)
	assert.True(t,
		subject == "graph.ingest.query.entity.v1" || subject == "graph.index.query.entity.v2",
		"should use one of the discovered subjects, got: %s", subject)

	// Verify it's NOT the fallback
	assert.NotEqual(t, "graph.ingest.query.entity", subject, "should not use fallback when routes discovered")
}

